import time
from contextlib import closing

class MonolithicLedgerEngine:
    def __init__(self):
        self.incoming_transactions = []
        self.active_accounts = {}
        self.platform_revenue = 0.0
        print("Booting Monolithic Fintech Ledger...")

    def load_account_data(self, filepath):
        """Load account data from a JSON file."""
        with open(filepath, 'r') as f:
            self.account_db = json.load(f)

    def activate_accounts(self):
        """Activate only non-frozen accounts."""
        self.active_accounts = {k: v for k, v in self.account_db.items() if not v.get('frozen')}

    def ingest_payment_stream(self, raw_payloads):
        """Parse incoming JSON transaction payloads."""
        for raw_str in raw_payloads:
            try:
                parsed = json.loads(raw_str)
                self.incoming_transactions.append(parsed)
            except json.JSONDecodeError as e:
                print(f"Failed to decode JSON: {e}")

    def process_transaction_batch(self):
        """Process batched transactions and update ledger."""
        with closing(open(f"ledger_audit_{int(time.time())}.log", "w")) as audit_log:
            audit_log.write("Timestamp,TxID,Sender,Receiver,Amount,Fee,Type,Status\n")

            for tx in self.incoming_transactions:
                if tx and 'tx_id' in tx and 'sender_id' in tx and 'receiver_id' in tx \
                   and 'amount' in tx and 'transfer_type' in tx:

                    s_id, r_id, amount, t_type = tx['sender_id'], tx['receiver_id'], tx['amount'], tx['transfer_type']
                    sender_acc = self.active_accounts.get(s_id)
                    receiver_acc = self.active_accounts.get(r_id)

                    if sender_acc and receiver_acc:
